import{_ as a,o,c as t,ag as n}from"./chunks/framework.CAXxHpAX.js";const v=JSON.parse('{"title":"秦始皇巩固统一的措施：","description":"","frontmatter":{},"headers":[],"relativePath":"notes/note-4.md","filePath":"notes/note-4.md"}'),e={name:"notes/note-4.md"};function r(s,p,l,c,d,i){return o(),t("div",null,[...p[0]||(p[0]=[n('<h1 id="秦始皇巩固统一的措施" tabindex="-1">秦始皇巩固统一的措施： <a class="header-anchor" href="#秦始皇巩固统一的措施" aria-label="Permalink to &quot;秦始皇巩固统一的措施：&quot;">​</a></h1><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">秦始皇巩固统一的措施：</span></p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">①统一文字：</span>小篆；</p><p>②统一度量衡；</p><p>③统一车轨；</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">④统一货币：</span>圆形方孔半两钱；</p><p>⑤统一岭南；</p><p>⑥派蒙恬北击匈奴，修东起辽东，西至临洮的长城；</p><p>⑦开凿灵渠。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">秦朝疆域：</span>东至东海，西到陇西，北至长城，南达南海。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">汉武帝巩固大一统王朝的措施：</span></p><p>①推恩令（主父偃），建立刺史制度；</p><p>②罢黜百家，尊崇儒术（董仲舒），把儒家学说立为正统思想，兴办太学；</p><p>③把铸币权收归中央，铸造五铢钱；实行盐铁官营专卖；</p><p>④派张骞出使西域；</p><p>⑤开辟陆上和海上丝绸之路；</p><p>⑥派卫青、霍去病北击匈奴。</p><p>汉武帝从政治、经济、思想和军事等方面巩固了大一统的局面，使西汉开始进入鼎盛时期。</p><p>1、战国、秦国、李冰、都江堰、成都平原、岷江。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">2、秦统一时间：</span>前221年，定都：咸阳。</p><p>3、秦朝建立了君主专制中央集权制度。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">4、影响：</span>奠定了中国两千多年封建政治制度的基本格局，为历代王朝所沿用。封建社会后期阻碍社会进步。</p><p>5、大泽乡起义、陈胜吴广、前209年，张楚政权，我国历史上第一次农民起义。沉重打击秦朝的统治。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">6、汉初，采取休养生息政策的皇帝有：</span>汉高祖（刘邦）、文帝、景帝。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">7、张骞第一次出使西域的目的：</span>联络大月氏夹击匈奴；第二次：加强与西域各国的联系。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">8、张骞出使西域的影响：</span>开辟了通往西域的道路，促进汉朝与西域各国的相互了解与往来。促进东西方经济文化交流，为丝绸之路开通奠基。</p><p>9、东汉末年的农民起义是黄巾起义，张角。</p><p>1</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">0、华佗：</span>东汉，麻沸散、外科手术、五禽戏</p><p>1</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">1、张仲景：</span>东汉，《伤寒杂病论》，治未病。</p>',31)])])}const f=a(e,[["render",r]]);export{v as __pageData,f as default};
